var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"기세가 밀리면 알아서 도망칠 줄 알았는데, 끈질기네요.","JPN":"不利になれば逃げると思ったのに、しつこいわね。","ENG":"I thought they'd leave once they realized we were stronger. But they're so persistent.","TWN":"本以為氣勢被壓倒後會逃跑的，沒想到這麼執著。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그럴 수 밖에. 침식체는 브레이크가 고장 난 불도저 같은 거니까.","JPN":"そりゃそうさ。侵食体はブレーキが壊れたブルドーザーのようなもんだから。","ENG":"Of course they are. C.O.s are like bulldozers with broken brakes.","TWN":"當然了，侵蝕體就像刹車失靈的推土機。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"굉장해.","JPN":"すごい。","ENG":"Incredible.","TWN":"棒極了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저 사람들. 그 많은 침식체들을 상대로 이겼어요.","JPN":"あの人たち。あの数の侵食体に勝ちました。","ENG":"Those people, they defeated all those C.O.s.","TWN":"那些傢伙竟然戰勝了那麼多的侵蝕體。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"레아 씨…? 왜 그래요?","JPN":"レアさん……？　どうしました？","ENG":"Leah...? What's wrong?","TWN":"蕾亞……？你怎麼了？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"날 노리던 녀석이 사라졌어.","JPN":"私を狙っていたやつが消えた。","ENG":"The C.O. that was after me is gone.","TWN":"追殺我的人消失了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그 녀석을 놓치면, 또 다시 우릴 찾아올 거야.","JPN":"そいつを逃がすと、また私を追いかけてくるはず。","ENG":"If we let him go, he'll come back for us.","TWN":"如果放走他，以後一定還會再來找我們的。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"저 두 사람… 평범한 조난자들은 아닌 것 같네.","JPN":"あの二人……ただの遭難者ではなさそうだね。","ENG":"Those two... don't look like ordinary victims.","TWN":"這兩個人……看起來不是普通的遇難者。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"사장님도 눈치 챘어?","JPN":"社長も気づいた？","ENG":"Did you notice that too, Boss?","TWN":"老闆也注意到了嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Yes.","TWN":"是的。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이쯤 되면 나한테 미녀복이 많다는 걸 인정하는 수밖에 없겠지.","JPN":"こうなると、私には美女が集まってくるということを認めざるをえないな。","ENG":"By now, I think I have no choice but to admit that I'm blessed with beautiful women.","TWN":"此時此刻，我不得不承認自己確實很有豔福。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"아니, 그런 거 말고.","JPN":"いや、そうじゃなくて。","ENG":"No, I wasn't talking about that.","TWN":"不，不是說那個。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"싸우는 내내 침식체들이 적극적으로 달려들었어. 저 두사람에게만.","JPN":"戦っている間に侵食体があの二人にだけ、積極的に攻撃してきたんだ。","ENG":"While we were fighting, the C.O.s only charged toward those two.","TWN":"戰鬥時，侵蝕體的目標始終是那兩個人。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미나 양의 예상이 맞을 걸세.","JPN":"ミナ君の予想通りだろう。","ENG":"What Mina suspects should be right.","TWN":"米娜的猜想可能是對的。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"침식체들이 유독 저들만 노린다는 건…","JPN":"侵食体が彼女たちだけを狙うということは……","ENG":"If C.O.s are only after those two...","TWN":"侵蝕體之所以只攻擊她們……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…저들 중 침식체들을 움직이게 하는 원인이 있다는 거겠지.","JPN":"……どちらかに侵食体を動かせる原因があるということになる。","ENG":"...Then one of them must be causing the C.O.s to move.","TWN":"……是因為她們當中有人在吸引著侵蝕體。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};